import { defineStore } from 'pinia'
import axios from 'axios'

export const useAuthStore = defineStore('auth', {
  state: () => ({
    token: localStorage.getItem('token') || null,
    user: JSON.parse(localStorage.getItem('user')) || null,
    tokenType: localStorage.getItem('tokenType') || 'bearer',
    expiresIn: Number(localStorage.getItem('expiresIn') || 0)
  }),
  actions: {
    async login(credentials) {
      const response = await axios.post('/auth/login', credentials)
      const data = response.data?.data || {}

      this.token = data.access_token || null
      this.tokenType = data.token_type || 'bearer'
      this.expiresIn = Number(data.expires_in || 0)
      this.user = data.user || null

      if (this.token) {
        localStorage.setItem('token', this.token)
      } else {
        localStorage.removeItem('token')
      }

      localStorage.setItem('tokenType', this.tokenType)
      localStorage.setItem('expiresIn', String(this.expiresIn))

      if (this.user) {
        localStorage.setItem('user', JSON.stringify(this.user))
      } else {
        localStorage.removeItem('user')
      }

      return data
    },
    async logout() {
      try {
        await axios.post('/auth/logout')
      } catch (error) {
        // Always clear local auth state even if API logout fails.
      }

      this.token = null
      this.user = null
      this.tokenType = 'bearer'
      this.expiresIn = 0
      localStorage.removeItem('token')
      localStorage.removeItem('user')
      localStorage.removeItem('tokenType')
      localStorage.removeItem('expiresIn')
    }
  }
})

